function cmToFtIn(cm){
  const totalIn = Math.round(cm/2.54);
  return `${Math.floor(totalIn/12)}' ${totalIn%12}"`;
}

function getFitRating(heightCm, evLcm){
  const margin = evLcm - heightCm;
  if(margin >= 15) return {label:'Comfortable', cls:'fit-good',  tip:'Plenty of room — you can sleep with legs straight.'};
  if(margin >= 5)  return {label:'Good Fit',    cls:'fit-good',  tip:'Works well. Push front seat forward for extra space.'};
  if(margin >= -5) return {label:'Tight',       cls:'fit-fair',  tip:'Possible with front seats pushed fully forward (+3–5").'};
  return             {label:'Not Recommended', cls:'fit-poor',  tip:'Too short even with seats adjusted. Consider diagonal sleeping.'};
}

function updateHeightRec(){
  const cm = parseInt(document.getElementById('height-slider').value);
  const inches = Math.round(cm/2.54);
  const ft = Math.floor(inches/12), inp = inches%12;
  document.getElementById('height-display').innerHTML =
    `${ft}' ${inp}" &nbsp;<span style="font-size:.9rem;color:var(--text3);font-weight:400">(${cm} cm)</span>`;

  const container = document.getElementById('height-rec-results');

  // Sort: comfortable first, then good fit, then tight, then not recommended
  const order = {Comfortable:0,'Good Fit':1,Tight:2,'Not Recommended':3};
  const sorted = [...evHeightData].sort((a,b)=>{
    const ra = getFitRating(cm,a.L_cm), rb = getFitRating(cm,b.L_cm);
    return (order[ra.label]||3) - (order[rb.label]||3);
  });

  container.innerHTML = sorted.map(ev => {
    const fit = getFitRating(cm, ev.L_cm);
    const campBadge = ev.camp==='Yes'
      ? `<span style="background:var(--success-bg);color:var(--success);padding:.15rem .45rem;border-radius:3px;font-size:.7rem;font-weight:700">✓ Camp Mode</span>`
      : `<span style="background:var(--warn-bg);color:var(--warn);padding:.15rem .45rem;border-radius:3px;font-size:.7rem;font-weight:700">No Camp Mode</span>`;
    const borderCol = fit.label==='Comfortable'||fit.label==='Good Fit' ? ev.color : fit.label==='Tight' ? '#c47a00' : '#ccc';
    return `
      <div style="background:var(--bg);border:2px solid ${borderCol};border-radius:8px;padding:1.1rem;transition:.2s;cursor:pointer" onclick="showPage('compare');onEVSelect('${ev.key}');document.getElementById('f-vehicle').value='${ev.key}'">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:.6rem;gap:.5rem">
          <div style="font-weight:700;font-size:.92rem;color:var(--text)">${ev.name}</div>
          <span class="fit-badge ${fit.cls}" style="white-space:nowrap;font-size:.72rem">${fit.label}</span>
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:.3rem .75rem;font-size:.8rem;margin-bottom:.65rem">
          <span style="color:var(--text3)">Sleep length</span><strong>${cmToFtIn(ev.L_cm)} (${ev.L_cm} cm)</strong>
          <span style="color:var(--text3)">Headroom</span><strong>${cmToFtIn(ev.H_cm)}</strong>
          <span style="color:var(--text3)">Climate</span>${campBadge}
        </div>
        <div style="font-size:.78rem;color:var(--text3);font-style:italic;margin-bottom:.6rem;line-height:1.4">${fit.tip}</div>
        <div style="border-top:1px solid var(--border);padding-top:.6rem;margin-top:.4rem">
          <div style="font-size:.72rem;font-weight:700;text-transform:uppercase;letter-spacing:.4px;color:var(--text3);margin-bottom:.25rem">Best mattress</div>
          <div style="font-size:.8rem;color:var(--primary);font-weight:600">${ev.mat}</div>
        </div>
        <div style="font-size:.75rem;color:var(--text2);margin-top:.5rem;line-height:1.4">${ev.note}</div>
      </div>`;
  }).join('');
}

// init on load
document.addEventListener('DOMContentLoaded', updateHeightRec);


