function flatBadge(flat){
  if(flat.startsWith('✓')||flat.includes('Nearly flat')||flat.includes('Flat (3rd')||flat.includes('Multiflex')||flat.includes('Fully flat'))
    return '<span style="background:var(--success-bg);color:var(--success);padding:.2rem .45rem;border-radius:4px;font-size:.75rem;font-weight:600">'+flat+'</span>';
  if(flat.includes('needs'))
    return '<span style="background:var(--danger-bg);color:var(--danger);padding:.2rem .45rem;border-radius:4px;font-size:.75rem;font-weight:600">'+flat+'</span>';
  return '<span style="background:var(--warn-bg);color:var(--warn);padding:.2rem .45rem;border-radius:4px;font-size:.75rem;font-weight:600">'+flat+'</span>';
}
function campBadge(camp){
  return camp.startsWith('✓')
    ? '<span style="background:var(--success-bg);color:var(--success);padding:.2rem .45rem;border-radius:4px;font-size:.75rem;font-weight:600">'+camp+'</span>'
    : '<span style="background:var(--warn-bg);color:var(--warn);padding:.2rem .45rem;border-radius:4px;font-size:.75rem;font-weight:600">'+camp+'</span>';
}

function renderAllEVTable(){
  var tbody=document.getElementById('ev-all-tbody');
  if(!tbody)return;
  var order=['id_buzz_tourer','id_buzz','model_x','ev9','r1s','cybertruck','f150_lightning','r1t','model_y','rivian_r2','ix','ioniq5','mach_e','equinox','bz4x','solterra','ex40','id4','kia_ev6','ioniq6','model_3','bolt','polestar2'];
  tbody.innerHTML=order.map(function(key,i){
    var e=evProfiles[key];
    return '<tr style="'+(i%2===1?'background:rgba(248,249,250,.5)':'')+'">'+
      '<td style="padding:.8rem 1rem;border-bottom:1px solid var(--border);font-weight:600;cursor:pointer;color:var(--primary)" onclick="document.getElementById(\'ev-select\').value=\''+key+'\';showEVProfile(\''+key+'\')">'+e.name+'</td>'+
      '<td style="padding:.8rem 1rem;border-bottom:1px solid var(--border);text-align:center;font-weight:700">'+e.L+'"</td>'+
      '<td style="padding:.8rem 1rem;border-bottom:1px solid var(--border);text-align:center;font-weight:700">'+e.W+'"</td>'+
      '<td style="padding:.8rem 1rem;border-bottom:1px solid var(--border);text-align:center;font-weight:700;'+(e.H<25?'color:var(--warn)':e.H>50?'color:var(--success)':'')+'">'+e.H+'"</td>'+
      '<td style="padding:.8rem 1rem;border-bottom:1px solid var(--border);font-size:.85rem">'+e.maxMat+'</td>'+
      '<td style="padding:.8rem 1rem;border-bottom:1px solid var(--border);text-align:center">'+flatBadge(e.flat)+'</td>'+
      '<td style="padding:.8rem 1rem;border-bottom:1px solid var(--border);text-align:center">'+campBadge(e.camp)+'</td>'+
      '<td style="padding:.8rem 1rem;border-bottom:1px solid var(--border);text-align:center;font-weight:600">'+e.down+' cu ft</td>'+
      '<td style="padding:.8rem 1rem;border-bottom:1px solid var(--border);font-size:.82rem;color:var(--text2)">'+e.notes.substring(0,70)+'…</td>'+
    '</tr>';
  }).join('');
}

function showEVProfile(key){
  var panel=document.getElementById('ev-profiles-individual');
  var allDiv=document.getElementById('ev-profiles-all');
  if(!key){allDiv.style.display='block';panel.style.display='none';return;}
  var e=evProfiles[key];
  allDiv.style.display='none';
  panel.style.display='block';
  var matchedMats=mattresses.filter(function(m){return m[key]==='Good';});
  var matRows=matchedMats.length?matchedMats.map(function(m){
    return '<tr><td style="padding:.55rem .75rem;border-bottom:1px solid var(--border);font-weight:600;font-size:.85rem">'+m.name+'</td>'+
      '<td style="padding:.55rem .75rem;border-bottom:1px solid var(--border);font-size:.83rem">$'+m.price+'</td>'+
      '<td style="padding:.55rem .75rem;border-bottom:1px solid var(--border);font-size:.83rem">'+m.weight_lbs+' lbs</td>'+
      '<td style="padding:.55rem .75rem;border-bottom:1px solid var(--border);font-size:.83rem"><span class="rval '+rvClass(m.rvalue)+'">'+m.rvalue+'</span></td>'+
      '<td style="padding:.55rem .75rem;border-bottom:1px solid var(--border);font-size:.83rem">'+m.type+'</td></tr>';
  }).join(''):'<tr><td colspan="5" style="padding:.75rem;color:var(--text3);font-size:.85rem">No mattresses currently rated Good for this EV — check back soon.</td></tr>';

  panel.innerHTML='<div style="border:2px solid '+e.color+';border-radius:8px;overflow:hidden;margin-bottom:2rem">'+
    '<div style="background:'+e.color+';padding:1.25rem 1.5rem;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:.5rem">'+
      '<div><div style="color:rgba(255,255,255,.7);font-size:.72rem;font-weight:700;text-transform:uppercase;letter-spacing:.5px;margin-bottom:.2rem">EV Camping Profile</div>'+
      '<div style="color:#fff;font-size:1.3rem;font-weight:700">'+e.name+'</div></div>'+
      '<button onclick="showAllEVs()" style="background:rgba(255,255,255,.15);border:1px solid rgba(255,255,255,.4);color:#fff;border-radius:5px;padding:.5rem .9rem;font-size:.82rem;font-weight:600;cursor:pointer">← All EVs</button>'+
    '</div>'+
    '<div style="padding:1.5rem;background:#fff">'+
      '<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:1rem;margin-bottom:1.5rem">'+
        '<div style="background:var(--bg);border-radius:6px;padding:1rem;text-align:center"><div style="font-size:1.8rem;font-weight:700;color:'+e.color+'">'+e.L+'"</div><div style="font-size:.72rem;color:var(--text3);text-transform:uppercase;letter-spacing:.4px;font-weight:600;margin-top:.2rem">Length</div></div>'+
        '<div style="background:var(--bg);border-radius:6px;padding:1rem;text-align:center"><div style="font-size:1.8rem;font-weight:700;color:'+e.color+'">'+e.W+'"</div><div style="font-size:.72rem;color:var(--text3);text-transform:uppercase;letter-spacing:.4px;font-weight:600;margin-top:.2rem">Width</div></div>'+
        '<div style="background:var(--bg);border-radius:6px;padding:1rem;text-align:center"><div style="font-size:1.8rem;font-weight:700;color:'+(e.H<25?'var(--warn)':e.H>50?'var(--success)':e.color)+'">'+e.H+'"</div><div style="font-size:.72rem;color:var(--text3);text-transform:uppercase;letter-spacing:.4px;font-weight:600;margin-top:.2rem">Headroom</div></div>'+
        '<div style="background:var(--bg);border-radius:6px;padding:1rem;text-align:center"><div style="font-size:1.8rem;font-weight:700;color:'+e.color+'">'+e.down+'</div><div style="font-size:.72rem;color:var(--text3);text-transform:uppercase;letter-spacing:.4px;font-weight:600;margin-top:.2rem">Cu ft (down)</div></div>'+
      '</div>'+
      '<div style="display:grid;grid-template-columns:1fr 1fr;gap:.6rem;margin-bottom:1.25rem;font-size:.88rem">'+
        '<div style="display:flex;gap:.5rem"><span style="color:var(--text3);min-width:115px;font-weight:500">Max mattress:</span><strong>'+e.maxMat+'</strong></div>'+
        '<div style="display:flex;gap:.5rem;align-items:center"><span style="color:var(--text3);min-width:115px;font-weight:500">Floor:</span>'+flatBadge(e.flat)+'</div>'+
        '<div style="display:flex;gap:.5rem;align-items:center"><span style="color:var(--text3);min-width:115px;font-weight:500">Camp Mode:</span>'+campBadge(e.camp)+'</div>'+
        '<div style="display:flex;gap:.5rem"><span style="color:var(--text3);min-width:115px;font-weight:500">Platform needed:</span><strong>'+(e.platform?'Yes — recommended':'No')+'</strong></div>'+
        '<div style="display:flex;gap:.5rem"><span style="color:var(--text3);min-width:115px;font-weight:500">Frunk:</span><strong>'+e.frunk+'</strong></div>'+
        '<div style="display:flex;gap:.5rem"><span style="color:var(--text3);min-width:115px;font-weight:500">Battery drain:</span><strong>'+e.campBattery+'</strong></div>'+
      '</div>'+
      '<div style="background:var(--bg);border-radius:6px;padding:1rem 1.1rem;margin-bottom:1rem;font-size:.9rem;color:var(--text2)">'+e.notes+'</div>'+
      '<div style="background:rgba(15,110,86,0.06);border-left:3px solid var(--primary);border-radius:4px;padding:.85rem 1rem;margin-bottom:1.5rem;font-size:.88rem"><strong>Setup tip:</strong> '+e.setup+'</div>'+
      '<h4 style="font-size:.8rem;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:var(--text3);margin-bottom:.65rem">Mattresses Rated Good for This EV</h4>'+
      '<div style="border:1px solid var(--border);border-radius:6px;overflow:hidden;margin-bottom:1rem">'+
        '<table style="width:100%;border-collapse:collapse;font-size:.88rem">'+
          '<thead><tr style="background:var(--bg)">'+
            '<th style="padding:.6rem .75rem;text-align:left;font-weight:600;border-bottom:2px solid var(--border)">Mattress</th>'+
            '<th style="padding:.6rem .75rem;text-align:left;font-weight:600;border-bottom:2px solid var(--border)">Price</th>'+
            '<th style="padding:.6rem .75rem;text-align:left;font-weight:600;border-bottom:2px solid var(--border)">Weight</th>'+
            '<th style="padding:.6rem .75rem;text-align:left;font-weight:600;border-bottom:2px solid var(--border)">R-Value</th>'+
            '<th style="padding:.6rem .75rem;text-align:left;font-weight:600;border-bottom:2px solid var(--border)">Type</th>'+
          '</tr></thead>'+
          '<tbody>'+matRows+'</tbody>'+
        '</table>'+
      '</div>'+
      '<button onclick="showPage(\'compare\');onEVSelect(\''+key+'\');document.getElementById(\'f-vehicle\').value=\''+key+'\'" style="background:'+e.color+';color:#fff;border:none;border-radius:5px;padding:.75rem 1.25rem;font-size:.88rem;font-weight:600;cursor:pointer">Filter Comparison Table for '+e.name+' →</button>'+
    '</div>'+
  '</div>';
  panel.scrollIntoView({behavior:'smooth',block:'start'});
}

function showAllEVs(){
  document.getElementById('ev-select').value='';
  document.getElementById('ev-profiles-individual').style.display='none';
  document.getElementById('ev-profiles-all').style.display='block';
}

function viewFullEVProfile(){
  if(!currentEV) return;
  // 1. Navigate to Guides page
  showPage('guides');
  // 2. Activate the EV Dimensions tab
  const tabBtn = document.getElementById('tab-btn-ev-dims');
  document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
  document.querySelectorAll('.tab-pane').forEach(p => p.classList.remove('active'));
  if(tabBtn) tabBtn.classList.add('active');
  const pane = document.getElementById('t-ev-dims');
  if(pane) pane.classList.add('active');
  // 3. Set the EV select and show the profile
  const sel = document.getElementById('ev-select');
  if(sel) sel.value = currentEV;
  showEVProfile(currentEV);
}
document.addEventListener('DOMContentLoaded',renderAllEVTable);


